# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import time
import logging
from datetime import datetime

app = Flask(__name__)

es = Elasticsearch(
    ['http://localhost:9200'],
    max_retries=3,
    retry_on_timeout=True,
    request_timeout=30
)

PRODUCTS_INDEX = 'products'

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def rate_limit(max_per_second=100):
    min_interval = 1.0 / max_per_second
    last_called = [0.0]
    
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            elapsed = time.time() - last_called[0]
            left_to_wait = min_interval - elapsed
            if left_to_wait > 0:
                time.sleep(left_to_wait)
            ret = func(*args, **kwargs)
            last_called[0] = time.time()
            return ret
        return wrapper
    return decorator


@app.route('/api/search', methods=['GET'])
def search_products():
    start_time = time.time()
    
    query_param = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    
    if not query_param:
        return jsonify({
            'error': 'Query parameter "q" is required',
            'status': 'error'
        }), 400
    
    if per_page > 100:
        per_page = 100
    
    if page < 1:
        page = 1
    
    from_index = (page - 1) * per_page
    
    try:
        search_body = {
            'query': {
                'bool': {
                    'should': [
                        {
                            'multi_match': {
                                'query': query_param,
                                'fields': ['name^3', 'description^2', 'category', 'brand', 'tags'],
                                'type': 'best_fields',
                                'fuzziness': 'AUTO'
                            }
                        },
                        {
                            'match_phrase': {
                                'name': {
                                    'query': query_param,
                                    'boost': 5
                                }
                            }
                        }
                    ],
                    'minimum_should_match': 1,
                    'filter': [
                        {'term': {'is_active': True}}
                    ]
                }
            },
            'from': from_index,
            'size': per_page,
            'sort': [
                {'_score': {'order': 'desc'}},
                {'popularity': {'order': 'desc'}}
            ],
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<em>'],
                'post_tags': ['</em>']
            },
            '_source': ['id', 'name', 'description', 'price', 'category', 'brand', 'image_url', 'stock', 'rating']
        }
        
        response = es.search(
            index=PRODUCTS_INDEX,
            body=search_body
        )
        
        hits = response['hits']
        total = hits['total']['value'] if isinstance(hits['total'], dict) else hits['total']
        
        products = []
        for hit in hits['hits']:
            product = hit['_source']
            product['score'] = hit['_score']
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            products.append(product)
        
        elapsed_time = time.time() - start_time
        
        result = {
            'status': 'success',
            'query': query_param,
            'total': total,
            'page': page,
            'per_page': per_page,
            'total_pages': (total + per_page - 1) // per_page,
            'products': products,
            'took_ms': round(elapsed_time * 1000, 2)
        }
        
        logger.info(f"Search query: '{query_param}' - Results: {len(products)} - Time: {elapsed_time:.3f}s")
        
        return jsonify(result), 200
        
    except Exception as e:
        logger.error(f"Search error for query '{query_param}': {str(e)}")
        return jsonify({
            'error': 'Search service temporarily unavailable',
            'status': 'error',
            'message': str(e)
        }), 503


@app.route('/api/search/suggest', methods=['GET'])
def search_suggestions():
    query_param = request.args.get('q', '').strip()
    
    if not query_param or len(query_param) < 2:
        return jsonify({
            'suggestions': []
        }), 200
    
    try:
        search_body = {
            'suggest': {
                'product-suggest': {
                    'prefix': query_param,
                    'completion': {
                        'field': 'name.suggest',
                        'size': 10,
                        'skip_duplicates': True
                    }
                }
            }
        }
        
        response = es.search(
            index=PRODUCTS_INDEX,
            body=search_body
        )
        
        suggestions = []
        if 'suggest' in response and 'product-suggest' in response['suggest']:
            for option in response['suggest']['product-suggest'][0]['options']:
                suggestions.append({
                    'text': option['text'],
                    'score': option['_score']
                })
        
        return jsonify({
            'suggestions': suggestions
        }), 200
        
    except Exception as e:
        logger.error(f"Suggestion error for query '{query_param}': {str(e)}")
        return jsonify({
            'suggestions': []
        }), 200


@app.route('/health', methods=['GET'])
def health_check():
    try:
        es.cluster.health()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': 'connected',
            'timestamp': datetime.utcnow().isoformat()
        }), 200
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': 'disconnected',
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 503


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)